import React, { useState, useEffect } from 'react';
import { fetchPerformanceData } from '../services/googleSheetsService';
import '../styles/PerformanceOverview.css';

function PerformanceOverview() {
  const [performanceData, setPerformanceData] = useState({
    thisWeek: '0',
    lastWeek: '0',
    monthly: '0',
    yearly: '0'
  });
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const data = await fetchPerformanceData();
        if (data) {
          setPerformanceData({
            thisWeek: data.thisWeek || '0',
            lastWeek: data.lastWeek || '0',
            monthly: data.monthly || '0',
            yearly: data.yearly || '0'
          });
        }
      } catch (err) {
        console.error('Error fetching performance data:', err);
        setError('Failed to load performance data');
      }
    };

    fetchData();
  }, []);

  const metrics = [
    { label: 'This Week', value: performanceData.thisWeek },
    { label: 'Last Week', value: performanceData.lastWeek },
    { label: 'Monthly PNL', value: performanceData.monthly },
    { label: 'Yearly PNL', value: performanceData.yearly }
  ];

  return (
    <div className="performance-cards-container">
      {metrics.map((metric, index) => (
        <div key={index} className="performance-card">
          <h3 className="performance-card-title">{metric.label}</h3>
          <p className={`performance-card-value ${parseFloat(metric.value) >= 0 ? 'positive' : 'negative'}`}>
            {parseFloat(metric.value) >= 0 ? '+' : ''}{metric.value}%
          </p>
        </div>
      ))}
    </div>
  );
}

export default PerformanceOverview;
