import React from 'react';
import DailyPNL from './DailyPNL';
import PerformanceOverview from './PerformanceOverview';
import TradeHistory from './TradeHistory';
import './Dashboard.css';
import { useEffect, useState } from 'react';
import { fetchTradeHistory } from '../services/api';
import { useNavigate } from 'react-router-dom';

function Dashboard() {
  const [tradeData, setTradeData] = useState([]);
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    const checkAuthAndLoadData = async () => {
      const token = localStorage.getItem('token');
      if (!token) {
        navigate('/login', { replace: true });
        return;
      }

      try {
        setLoading(true);
        const data = await fetchTradeHistory();
        setTradeData(data);
        setError('');
      } catch (error) {
        console.error('Load error:', error);
        if (error.message.includes('Authentication failed') || error.message.includes('No authentication token found')) {
          localStorage.removeItem('token');
          navigate('/login', { replace: true });
        } else {
          setError('Failed to load trade history');
        }
      } finally {
        setLoading(false);
      }
    };

    checkAuthAndLoadData();
  }, [navigate]);

  if (loading) return <div className="loading-container">Loading...</div>;
  if (error) return <div className="error-container">{error}</div>;

  return (
    <div className="dashboard">
      <DailyPNL />
      <PerformanceOverview />
      <TradeHistory isDashboard={true} data={tradeData} />
    </div>
  );
}

export default Dashboard;
