import React, { useEffect, useState } from 'react';
import { Bar } from 'react-chartjs-2';
import { fetchPNLData } from '../services/googleSheetsService';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend
} from 'chart.js';
import '../styles/PNLChart.css';

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend
);

function DailyPNL() {
  const [chartData, setChartData] = useState({
    labels: [],
    datasets: [],
  });
  const [error, setError] = useState(null);

  const fetchTradeData = async () => {
    try {
      const pnlData = await fetchPNLData();
      console.log('Raw PNL data:', pnlData); // Debug log

      if (!Array.isArray(pnlData) || pnlData.length === 0) {
        setError('No PNL data available');
        return;
      }

      const validData = pnlData
        .filter(item => item && item.date && !isNaN(parseFloat(item.pnl)))
        .map(item => ({
          date: new Date(item.date),
          pnl: parseFloat(item.pnl)
        }))
        .sort((a, b) => a.date - b.date);

      console.log('Processed valid data:', validData); // Debug log

      if (validData.length === 0) {
        setError('No valid PNL data after processing');
        return;
      }

      const recentTrades = validData.slice(-31);
      const labels = recentTrades.map(item => 
        item.date.toLocaleDateString('en-GB', { day: '2-digit', month: '2-digit' })
      );
      const data = recentTrades.map(item => item.pnl);

      setChartData({
        labels,
        datasets: [{
          label: 'Daily PNL',
          data,
          backgroundColor: data.map(pnl => pnl >= 0 ? 'rgba(0, 255, 0, 0.8)' : 'rgba(255, 0, 0, 0.8)'),
          borderColor: data.map(pnl => pnl >= 0 ? 'rgba(0, 255, 0, 1)' : 'rgba(255, 0, 0, 1)'),
          borderWidth: 1,
          barThickness: 5,
        }]
      });
      setError(null);
    } catch (error) {
      console.error('Error fetching PNL data:', error);
      setError('Failed to load PNL data');
    }
  };

  useEffect(() => {
    fetchTradeData();
  }, []);

  if (error) {
    return <div className="error-message">{error}</div>;
  }

  const options = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: {
        display: false,
      },
      tooltip: {
        enabled: true,
      },
      datalabels: {
        display: false, // Ensure this is set to false to disable data labels on the bars
      },
    },
    scales: {
      x: {
        grid: {
          color: 'rgba(255, 255, 255, 0.1)',
        },
        ticks: {
          color: 'grey',
        },
      },
      y: {
        grid: {
          color: 'rgba(255, 255, 255, 0.1)',
        },
        ticks: {
          color: 'grey',
          callback: function(value) {
            return value + '%'; // Add percentage sign to Y-axis labels
          },
        },
        min: -40, // Set minimum value to -50%
        max: 30,  // Set maximum value to 50%
      },
    },
  };

  return (
    <div className="daily-pnl-chart-container" style={{ height: '400px', marginTop: '-15px' }}>
      <Bar data={chartData} options={options} />
    </div>
  );
}

export default DailyPNL;
